mapper.select:
select b.id, b.title, b.first_picture, b.first_picture_asset_id, b.content, b.description, b.is_recommend, b.is_published, b.is_internal, b.is_appreciation,
b.is_comment_enabled, b.is_top, b.create_time, b.update_time, b.views, b.words, b.read_time,
c.id as category_id, c.category_name, c.color as category_color,
bt.tag_id as tag_id, t.tag_name as tag_name, t.color
from (((blog as b left join category as c on b.category_id=c.id) left join blog_tag as bt on b.id=bt.blog_id) left join tag as t on bt.tag_id=t.id)
where b.id=#{id}

